// ─── ECON STUDIO · services/export/replicationBundle.js ──────────────────────
// Builds a self-contained replication ZIP for a single estimated model.
//
// Contents:
//   README.txt            — human-readable description of all files
//   replication.R         — R script (fixest / rdrobust / modelsummary)
//   replication.py        — Python script (statsmodels / linearmodels)
//   replication.do        — Stata do-file (reghdfe / rdrobust / esttab)
//   data_dictionary.csv   — variable labels (if dataDictionary is non-empty)
//   pipeline.json         — serialised pipeline steps (if pipeline is non-empty)
//
// Usage:
//   import { buildReplicationBundle } from "./replicationBundle.js";
//   const zipBytes = await buildReplicationBundle(config);
//   // zipBytes is a Uint8Array — hand to Blob + anchor download

import { zipSync, strToU8 } from "fflate";
import { generateRScript }      from "./rScript.js";
import { generatePythonScript } from "./pythonScript.js";
import { generateStataScript }  from "./stataScript.js";
import { auditPipeline, auditTrailToMarkdown } from "../../pipeline/auditor.js";

// ─── HELPERS ──────────────────────────────────────────────────────────────────
function dictToCsv(dict) {
  const header = "variable,description";
  const rows = Object.entries(dict ?? {}).map(([k, v]) => {
    const safe = String(v ?? "").replace(/"/g, '""');
    return `${k},"${safe}"`;
  });
  return [header, ...rows].join("\n");
}

function buildReadme({ filename, model, ts, hasDict, hasPipeline, hasAudit }) {
  return [
    `ECON STUDIO — REPLICATION PACKAGE`,
    `${"─".repeat(50)}`,
    `Dataset  : ${filename}`,
    `Estimator: ${model?.type ?? "OLS"}`,
    `Created  : ${ts}`,
    ``,
    `FILES IN THIS BUNDLE`,
    `${"─".repeat(50)}`,
    ``,
    `replication.R`,
    `  Complete R script using fixest, rdrobust, and modelsummary.`,
    `  Reproduces data cleaning pipeline, estimation, and output table.`,
    `  Requires: dplyr, fixest, modelsummary (install.packages at top of file).`,
    ``,
    `replication.py`,
    `  Python script using pandas, statsmodels, and linearmodels.`,
    `  Requires: pandas, numpy, statsmodels (pip install).`,
    ``,
    `replication.do`,
    `  Stata do-file using reghdfe, rdrobust, and esttab.`,
    `  Requires: Stata 17+; install reghdfe and estout via ssc if needed.`,
    ``,
    hasDict ? [
      `data_dictionary.csv`,
      `  CSV with two columns: variable, description.`,
      `  Maps column names to human-readable labels and units.`,
      ``,
    ].join("\n") : "",
    hasPipeline ? [
      `pipeline.json`,
      `  Machine-readable pipeline steps (JSON). Can be re-imported into`,
      `  Econ Studio via File → Load Pipeline.`,
      ``,
    ].join("\n") : "",
    hasAudit ? [
      `audit_trail.md`,
      `  Step-by-step audit of every pipeline operation: what was done, how many`,
      `  rows/columns were affected, and the reasoning behind each decision.`,
      ``,
    ].join("\n") : "",
    `NOTES`,
    `${"─".repeat(50)}`,
    `• All scripts load the dataset from "${filename}" in the working directory.`,
    `• AI-generated transformations and mutate() steps may require manual review.`,
    `• Generated by Econ Studio — https://github.com/your-org/econ-studio`,
    ``,
  ].filter(l => l !== undefined).join("\n");
}

// ─── MAIN ─────────────────────────────────────────────────────────────────────
// Returns a Uint8Array (raw ZIP bytes). Caller creates Blob + triggers download.
// config.rawData: { rows, headers } — optional; if provided, audit trail is included.
export function buildReplicationBundle(config) {
  const {
    filename        = "dataset.csv",
    pipeline        = [],
    model           = {},
    dataDictionary  = null,
    auditTrail      = null,   // pre-computed AuditTrail (from auditor.js), or null
    rawData         = null,   // { rows, headers } — used to compute audit trail if not pre-computed
    context         = {},
  } = config;

  const ts         = new Date().toISOString().slice(0, 10);
  const stem       = filename.replace(/\.[^.]+$/, "");
  const hasDict    = dataDictionary && Object.keys(dataDictionary).length > 0;
  const hasPipeline = pipeline?.length > 0;

  // Compute audit trail if not pre-computed and rawData is available
  let resolvedTrail = auditTrail;
  if (!resolvedTrail && rawData?.rows && rawData?.headers && hasPipeline) {
    try { resolvedTrail = auditPipeline(rawData.rows, rawData.headers, pipeline, context); }
    catch { resolvedTrail = null; }
  }
  const hasAudit = !!resolvedTrail;

  // ── Generate scripts ──────────────────────────────────────────────────────
  const rScript    = generateRScript(config);
  const pyScript   = generatePythonScript(config);
  const stataScript = generateStataScript(config);
  const readme     = buildReadme({ filename, model, ts, hasDict, hasPipeline, hasAudit });

  // ── Build ZIP file map ────────────────────────────────────────────────────
  const files = {
    "README.txt":      strToU8(readme),
    "replication.R":   strToU8(rScript),
    "replication.py":  strToU8(pyScript),
    "replication.do":  strToU8(stataScript),
  };

  if (hasDict) {
    files["data_dictionary.csv"] = strToU8(dictToCsv(dataDictionary));
  }
  if (hasPipeline) {
    files["pipeline.json"] = strToU8(JSON.stringify(pipeline, null, 2));
  }
  if (hasAudit) {
    files["audit_trail.md"] = strToU8(auditTrailToMarkdown(resolvedTrail));
  }

  return zipSync(files, { level: 6 });
}

// ─── TRIGGER DOWNLOAD ─────────────────────────────────────────────────────────
// Helper for the UI layer — avoids importing fflate in the component.
export function downloadReplicationBundle(config) {
  const bytes  = buildReplicationBundle(config);
  const stem   = (config.filename ?? "analysis").replace(/\.[^.]+$/, "");
  const model  = config.model?.type ?? "model";
  const ts     = new Date().toISOString().slice(0, 10);

  const blob = new Blob([bytes], { type: "application/zip" });
  const a    = document.createElement("a");
  a.href     = URL.createObjectURL(blob);
  a.download = `${stem}_${model}_replication_${ts}.zip`;
  a.click();
  URL.revokeObjectURL(a.href);
}
